        Task<IOBPv400DeleteExplicitCounterpartyApiResponse> OBPv400DeleteExplicitCounterpartyAsync(string bankid, string accountid, string viewid, string counterpartyid, System.Threading.CancellationToken cancellationToken = default);

        /// <summary>
