        public async Task<IOBPv300CreateViewForBankAccountApiResponse?> OBPv300CreateViewForBankAccountOrDefaultAsync(string bankid, string accountid, OBPv600CreateCustomViewManagementRequest oBPv600CreateCustomViewManagementRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await OBPv300CreateViewForBankAccountAsync(bankid, accountid, oBPv600CreateCustomViewManagementRequest, cancellationToken).ConfigureAwait(false);
