        public async Task<IOBPv400GetAccountsByAccountRoutingRegexApiResponse?> OBPv400GetAccountsByAccountRoutingRegexOrDefaultAsync(OBPv400GetAccountsByAccountRoutingRegexRequest oBPv400GetAccountsByAccountRoutingRegexRequest, System.Threading.CancellationToken cancellationToken = default)
