        private void AfterOBPv510CreateUserWithAccountAccessByIdDefaultImplementation(IOBPv510CreateUserWithAccountAccessByIdApiResponse apiResponseLocalVar, string bankid, string accountid, string viewid, OBPv510CreateUserWithAccountAccessByIdRequest oBPv510CreateUserWithAccountAccessByIdRequest)
        {
            bool suppressDefaultLog = false;
            AfterOBPv510CreateUserWithAccountAccessById(ref suppressDefaultLog, apiResponseLocalVar, bankid, accountid, viewid, oBPv510CreateUserWithAccountAccessByIdRequest);
            if (!suppressDefaultLog)
                Logger.LogInformation("{0,-9} | {1} | {2}", (apiResponseLocalVar.DownloadedAt - apiResponseLocalVar.RequestedAt).TotalSeconds, apiResponseLocalVar.StatusCode, apiResponseLocalVar.Path);
        }

