        /// </summary>
        /// <exception cref="ApiException">Thrown when fails to make API call</exception>
        /// <param name="bankid">The BANKID identifier</param>
        /// <param name="accountid">The ACCOUNTID identifier</param>
        /// <param name="oBPv600CreateCustomViewManagementRequest">Request body</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="IOBPv600CreateCustomViewManagementApiResponse"/>&gt;</returns>
        public async Task<IOBPv600CreateCustomViewManagementApiResponse> OBPv600CreateCustomViewManagementAsync(string bankid, string accountid, OBPv600CreateCustomViewManagementRequest oBPv600CreateCustomViewManagementRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            UriBuilder uriBuilderLocalVar = new UriBuilder();

            try
            {
                ValidateOBPv600CreateCustomViewManagement(bankid, accountid, oBPv600CreateCustomViewManagementRequest);

