        public async Task<IOBPv600GetTransactionsForBankAccountApiResponse?> OBPv600GetTransactionsForBankAccountOrDefaultAsync(string bankid, string accountid, string viewid, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await OBPv600GetTransactionsForBankAccountAsync(bankid, accountid, viewid, cancellationToken).ConfigureAwait(false);
